using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new ShoppingCart();
    }

    #region AddItem Tests

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _sut.AddItem("SKU-001", 2, 9.99m);

        Assert.AreEqual(19.98m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_SumsAllItems()
    {
        _sut.AddItem("SKU-001", 1, 10.00m);
        _sut.AddItem("SKU-002", 3, 5.00m);

        Assert.AreEqual(25.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_AccumulatesQuantity()
    {
        _sut.AddItem("SKU-001", 1, 10.00m);
        _sut.AddItem("SKU-001", 2, 10.00m);

        Assert.AreEqual(30.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void AddItem_InvalidSku_ThrowsArgumentException(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.AddItem(sku!, 1, 10.00m));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void AddItem_InvalidQuantity_ThrowsArgumentException(int quantity)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.AddItem("SKU-001", quantity, 10.00m));
    }

    [TestMethod]
    [DataRow(-1.00)]
    [DataRow(-0.01)]
    public void AddItem_NegativePrice_ThrowsArgumentException(double price)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.AddItem("SKU-001", 1, (decimal)price));
    }

    #endregion

    #region RemoveItem Tests

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _sut.AddItem("SKU-001", 2, 10.00m);
        _sut.AddItem("SKU-002", 1, 5.00m);

        _sut.RemoveItem("SKU-001");

        Assert.AreEqual(5.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_OnlyItem_CartBecomesEmpty()
    {
        _sut.AddItem("SKU-001", 1, 15.00m);

        _sut.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(() => _sut.RemoveItem("NO-SUCH-SKU"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void RemoveItem_InvalidSku_ThrowsArgumentException(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.RemoveItem(sku!));
    }

    #endregion

    #region CalculateTotal Tests

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReflectsCurrentState()
    {
        _sut.AddItem("SKU-001", 2, 10.00m);
        _sut.AddItem("SKU-002", 1, 7.50m);
        _sut.RemoveItem("SKU-001");

        Assert.AreEqual(7.50m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_LargeQuantity_ComputesCorrectly()
    {
        _sut.AddItem("BULK-001", 1000, 0.99m);

        Assert.AreEqual(990.00m, _sut.CalculateTotal());
    }

    #endregion

    #region ApplyCoupon Tests

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _sut.AddItem("SKU-001", 1, 100.00m);

        _sut.ApplyCoupon("SAVE10");

        Assert.IsTrue(_sut.CalculateTotal() < 100.00m);
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCart_DoesNotThrow()
    {
        // Should handle gracefully even with no items
        _sut.ApplyCoupon("SAVE10");

        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException(string? code)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.ApplyCoupon(code!));
    }

    [TestMethod]
    public void ApplyCoupon_UnrecognizedCode_ThrowsInvalidOperationException()
    {
        _sut.AddItem("SKU-001", 1, 50.00m);

        Assert.ThrowsException<InvalidOperationException>(() => _sut.ApplyCoupon("FAKECODE"));
    }

    #endregion
}

